mapper.select:
select i.id, i.member_id as member_id, m.nickname as member_nickname, m.email as member_email, i.category, i.content, i.reply, i.status, i.created_datetime as created_datetime, i.updated_datetime as updated_datetime from tbl_inquiry i left join tbl_member m on i.member_id = m.id
and i.status = #{status}
and i.category = #{category}
and i.member_id = #{memberId}
order by i.created_datetime desc limit #{size} offset (#{page} - 1) * #{size}

select count(*)
from tbl_inquiry i


        and i.status = #{status}


        and i.category = #{category}


        and i.member_id = #{memberId}
